646	// heartbeatIsStale returns true if the given bead's Extra map has no
647	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
648	func heartbeatIsStale(extra map[string]any) bool {
649		if extra == nil {
650			return true
651		}
652		raw, ok := extra["execute-loop-heartbeat-at"]
653		if !ok {
654			return true
655		}
656		s, ok := raw.(string)
657		if !ok || s == "" {
658			return true
659		}
660		t, err := time.Parse(time.RFC3339Nano, s)
661		if err != nil {
662			// Fall back to RFC3339 for compatibility with legacy entries written
663			// before sub-second resolution. RFC3339Nano is the current canonical
664			// format used by both ClaimWithOptions and Heartbeat write sites.
665			t, err = time.Parse(time.RFC3339, s)
666			if err != nil {
667				return true
668			}
669		}
670		return time.Since(t) > HeartbeatTTL
671	}
