761	func (s *Store) AppendEvent(id string, event BeadEvent) error {
762		if event.CreatedAt.IsZero() {
763			event.CreatedAt = time.Now().UTC()
764		}
765		// Defense in depth: cap every event body regardless of caller. The
766		// reviewer write path separately persists the full stream to an artifact
767		// and emits a <=512-byte body; this cap catches anything else.
768		event.Body = capFieldBytes(event.Body)
769		event.Summary = capFieldBytes(event.Summary)
770		// Two storage shapes are possible here: inline Extra["events"] for active
771		// beads, and a sidecar attachment for closed/archived beads (ADR-004
772		// attachment model). When the bead has been externalized we append to the
773		// sidecar and leave the row untouched aside from updated_at.
774		var appendedToAttachment bool
775		if err := s.Update(id, func(b *Bead) {
776			if b.Extra == nil {
777				b.Extra = make(map[string]any)
778			}
779			if hasEventsAttachment(b) {
780				appendedToAttachment = true
781				return
782			}
783			var events []BeadEvent
784			if raw, ok := b.Extra["events"]; ok {
785				events = decodeBeadEvents(raw)
786			}
787			events = append(events, event)
788			b.Extra["events"] = encodeEventsForExtra(events)
789		}); err != nil {
790			return err
791		}
792		if !appendedToAttachment {
793			return nil
794		}
795		// Append to the sidecar under the store lock so concurrent readers and
796		// writers see a consistent events log.
797		return s.WithLock(func() error {
798			existing, err := s.readEventsAttachment(id)
799			if err != nil {
800				return err
801			}
802			existing = append(existing, event)
803			return s.writeEventsAttachment(id, existing)
804		})
805	}
