843	func decodeBeadEvents(raw any) []BeadEvent {
844		switch v := raw.(type) {
845		case []BeadEvent:
846			out := make([]BeadEvent, len(v))
847			copy(out, v)
848			return out
849		case []any:
850			out := make([]BeadEvent, 0, len(v))
851			for _, item := range v {
852				m, ok := item.(map[string]any)
853				if !ok {
854					continue
855				}
856				out = append(out, beadEventFromMap(m))
857			}
858			return out
859		case []map[string]any:
860			out := make([]BeadEvent, 0, len(v))
861			for _, item := range v {
862				out = append(out, beadEventFromMap(item))
863			}
864			return out
865		default:
866			return nil
867		}
868	}
