870	func beadEventFromMap(m map[string]any) BeadEvent {
871		e := BeadEvent{}
872		if v, ok := m["kind"].(string); ok {
873			e.Kind = v
874		}
875		if v, ok := m["summary"].(string); ok {
876			e.Summary = v
877		}
878		if v, ok := m["body"].(string); ok {
879			e.Body = v
880		}
881		if v, ok := m["actor"].(string); ok {
882			e.Actor = v
883		}
884		if v, ok := m["source"].(string); ok {
885			e.Source = v
886		}
887		if v, ok := m["created_at"].(string); ok {
888			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
889				e.CreatedAt = parsed
890			}
891		}
892		return e
893	}
