934	// ErrClosureGateRejected indicates a close was refused because the bead does
935	// not carry the evidence required for an automated closure: a terminal
936	// verdict event (review APPROVE with non-empty rationale, or an explicit
937	// review-skipped / manual-close marker) AND an execution-evidence marker
938	// (closing_commit_sha, session_id, or an execute-bead success event in the
939	// events history).
940	//
941	// Automated execute-loop paths (execute-bead + reviewer) always go through
942	// CloseWithEvidence. The plain Store.Close remains as the manual
943	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
944	// acceptance §1).
945	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
946	
947	// ClosureGate inspects a bead and returns nil iff the close is safe. It
948	// rejects only the specific shapes that caused the 2026-04-18/20
949	// review-malfunction incidents:
950	//
951	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
952	//     closing_commit_sha. Rejected by the execution-evidence check —
953	//     closing_commit_sha must be non-empty OR at least one event must exist.
954	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
955	//     body is empty. Rejected — APPROVE with no rationale is exactly the
956	//     parse-mis-extract shape the reviewer bug produced.
957	//
958	// Beads without a review step (--no-review, no Reviewer configured, already-
959	// satisfied paths) pass the gate as long as they carry execution evidence.
960	// This keeps the surface small: the gate catches known-bad shapes, not every
961	// conceivable edge case. Additional invariants belong in future dedicated
962	// beads so the rejection reason stays auditable.
963	func ClosureGate(b *Bead) error {
964		if b == nil {
965			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
966		}
967		hasClosingCommit := false
968		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
969			hasClosingCommit = true
970		}
971		events := decodeBeadEvents(b.Extra["events"])
972		// Externalized events still count as evidence for the gate. We only need
973		// to know whether *some* event history exists, not iterate it; the
974		// gate's APPROVE-with-empty-rationale check below relies on inline events
975		// (the verdict is recorded before externalization).
976		hasAttachedEvents := hasEventsAttachment(b)
977		// Reject the axon-c5cc071a shape: no events AND no closing commit.
978		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
979			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
980		}
981		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
982		for _, e := range events {
983			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
984				if strings.TrimSpace(e.Body) == "" {
985					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
986				}
987			}
988		}
989		return nil
990	}
