992	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
993	// sessionID is the agent session that completed the work.
994	// commitSHA is the exact closing commit SHA when it is known.
995	//
996	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
997	// via this path without a terminal verdict event plus execution evidence.
998	// Store.Close is the manual-administration escape hatch when the gate is
999	// inappropriate.
1000	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1001		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1002			return err
1003		}
1004		// Externalize events only when the gate actually transitioned the bead
1005		// to closed; rejected closes leave the bead open and inline.
1006		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1007			if err := s.externalizeEvents(id); err != nil {
1008				return err
1009			}
1010		}
1011		s.maybeOpportunisticArchive()
1012		return nil
1013	}
