1015	func (s *Store) closeWithEvidence(id string, sessionID string, commitSHA string) error {
1016		return s.Update(id, func(b *Bead) {
1017			if b.Extra == nil {
1018				b.Extra = make(map[string]any)
1019			}
1020			if sessionID != "" {
1021				b.Extra["session_id"] = sessionID
1022			}
1023			if commitSHA != "" {
1024				b.Extra["closing_commit_sha"] = commitSHA
1025			}
1026			if err := ClosureGate(b); err != nil {
1027				// Surface via bead notes so a later operator audit can see why the
1028				// close was refused; a single error path would be dropped by the
1029				// Update callback signature (no error return).
1030				appendClosureRejectNote(b, err)
1031				return
1032			}
1033			b.Status = StatusClosed
1034		})
1035	}
