1037	func appendClosureRejectNote(b *Bead, err error) {
1038		stamp := time.Now().UTC().Format(time.RFC3339)
1039		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
1040		if b.Notes == "" {
1041			b.Notes = note
1042			return
1043		}
1044		b.Notes = b.Notes + "\n" + note
1045	}
