1062	// Reopen sets a bead's status back to open, clears claim fields, optionally
1063	// appends notes, and records an immutable reopen event — all in one atomic
1064	// lock acquisition.
1065	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1066		now := time.Now().UTC()
1067		return s.WithLock(func() error {
1068			beads, _, err := s.readAllLatestRaw()
1069			if err != nil {
1070				return err
1071			}
1072			found := false
1073			for i := range beads {
1074				if beads[i].ID != id {
1075					continue
1076				}
1077				b := &beads[i]
1078				b.Status = StatusOpen
1079				b.Owner = ""
1080				b.UpdatedAt = now
1081				if b.Extra == nil {
1082					b.Extra = make(map[string]any)
1083				}
1084				// Clear claim fields
1085				delete(b.Extra, "claimed-at")
1086				delete(b.Extra, "claimed-pid")
1087				delete(b.Extra, "claimed-machine")
1088				delete(b.Extra, "claimed-session")
1089				delete(b.Extra, "claimed-worktree")
1090				delete(b.Extra, "execute-loop-heartbeat-at")
1091				// Append notes
1092				if appendNotes != "" {
1093					if b.Notes != "" {
1094						b.Notes = b.Notes + "\n\n" + appendNotes
1095					} else {
1096						b.Notes = appendNotes
1097					}
1098				}
1099				// Record reopen event. If events were externalized at close,
1100				// pull them back inline so the active row carries the full
1101				// history again and the attachment ref is dropped.
1102				if hasEventsAttachment(b) {
1103					if err := s.inlineEventsInPlace(b); err != nil {
1104						return err
1105					}
1106					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1107				}
1108				var events []BeadEvent
1109				if raw, ok := b.Extra["events"]; ok {
1110					events = decodeBeadEvents(raw)
1111				}
1112				evt := BeadEvent{
1113					Kind:      "reopen",
1114					CreatedAt: now,
1115				}
1116				if reason != "" {
1117					evt.Summary = reason
1118				}
1119				events = append(events, evt)
1120				encoded := make([]map[string]any, 0, len(events))
1121				for _, e := range events {
1122					encoded = append(encoded, map[string]any{
1123						"kind":       e.Kind,
1124						"summary":    e.Summary,
1125						"body":       e.Body,
1126						"actor":      e.Actor,
1127						"created_at": e.CreatedAt,
1128						"source":     e.Source,
1129					})
1130				}
1131				b.Extra["events"] = encoded
1132				if err := s.validateBead(b); err != nil {
1133					return err
1134				}
1135				if err := s.runHook("validate-bead-update", b); err != nil {
1136					return err
1137				}
1138				found = true
1139				break
1140			}
1141			if !found {
1142				return fmt.Errorf("bead: not found: %s", id)
1143			}
1144			return s.WriteAll(beads)
1145		})
1146	}
