1157	// List returns beads matching optional filters.
1158	// where is an optional map of key=value predicates that match against
1159	// known struct fields and Extra (unknown/workflow-specific) fields.
1160	func (s *Store) List(status, label string, where map[string]string) ([]Bead, error) {
1161		beads, err := s.ReadAll()
1162		if err != nil {
1163			return nil, err
1164		}
1165		var result []Bead
1166		for _, b := range beads {
1167			if status != "" && b.Status != status {
1168				continue
1169			}
1170			if label != "" && !containsString(b.Labels, label) {
1171				continue
1172			}
1173			if !matchesWhere(b, where) {
1174				continue
1175			}
