1181	// matchesWhere returns true if the bead satisfies all key=value predicates.
1182	// It checks known struct fields first, then falls back to Extra.
1183	func matchesWhere(b Bead, where map[string]string) bool {
1184		for k, v := range where {
1185			var actual string
1186			switch k {
1187			case "id":
1188				actual = b.ID
1189			case "title":
1190				actual = b.Title
1191			case "status":
1192				actual = b.Status
1193			case "issue_type":
1194				actual = b.IssueType
1195			case "owner":
1196				actual = b.Owner
1197			case "assignee":
1198				actual = b.Owner
1199			case "parent":
1200				actual = b.Parent
1201			case "description":
1202				actual = b.Description
1203			case "acceptance":
1204				actual = b.Acceptance
1205			case "notes":
1206				actual = b.Notes
1207			default:
1208				// Fall back to Extra map for unknown/workflow-specific fields
1209				if b.Extra != nil {
1210					if ev, ok := b.Extra[k]; ok {
1211						actual = fmt.Sprintf("%v", ev)
1212					}
1213				}
1214			}
1215			if actual != v {
1216				return false
1217			}
1218		}
1219		return true
1220	}
