1234	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1235	// they are NOT execution-eligible: epic containers, retry cooldown,
1236	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1237	// emits when the execution queue is empty but `ddx bead ready` is not.
1238	type ReadyExecutionBreakdown struct {
1239		SkippedEpics       []string
1240		SkippedOnCooldown  []string
1241		SkippedNotEligible []string
1242		SkippedSuperseded  []string
1243		NextRetryAfter     string
1244	}
1245	
1246	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1247		out := ReadyExecutionBreakdown{}
1248		ready, err := s.Ready()
1249		if err != nil {
1250			return out, err
1251		}
1252		now := time.Now().UTC()
1253		var soonestRetry time.Time
1254		for _, b := range ready {
1255			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1256				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1257					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1258						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1259						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1260							soonestRetry = retryAfter
1261						}
1262						continue
1263					}
1264				}
1265			}
1266			if eligible, ok := b.Extra["execution-eligible"]; ok {
1267				if val, isBool := eligible.(bool); isBool && !val {
1268					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1269					continue
1270				}
1271			}
1272			if sup, ok := b.Extra["superseded-by"]; ok {
1273				if s, isStr := sup.(string); isStr && s != "" {
1274					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1275					continue
1276				}
1277			}
1278		}
1279		if !soonestRetry.IsZero() {
1280			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1281		}
1282		return out, nil
1283	}
1284	
1285	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1286		beads, err := s.ReadAll()
1287		if err != nil {
1288			return nil, err
1289		}
1290		statusMap := make(map[string]string)
1291		for _, b := range beads {
1292			statusMap[b.ID] = b.Status
1293		}
1294	
1295		var ready []Bead
1296		for _, b := range beads {
1297			if b.Status != StatusOpen {
1298				// Surface stalled in_progress beads so a fresh worker can
1299				// reclaim them atomically in Claim().
1300				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1301					// fall through to dependency check below
1302				} else {
1303					continue
1304				}
1305			}
1306			allSatisfied := true
1307			for _, depID := range b.DepIDs() {
1308				if statusMap[depID] != StatusClosed {
1309					allSatisfied = false
1310					break
1311				}
1312			}
1313			if !allSatisfied {
1314				continue
1315			}
1316			if executionOnly {
1317				// Filter by execution-eligible (default true if absent)
1318				eligible, ok := b.Extra["execution-eligible"]
1319				if ok {
1320					if val, isBool := eligible.(bool); isBool && !val {
1321						continue
1322					}
1323				}
1324				// Filter out superseded beads
1325				if sup, ok := b.Extra["superseded-by"]; ok {
1326					if s, isStr := sup.(string); isStr && s != "" {
1327						continue
1328					}
1329				}
1330				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1331					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1332						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1333							continue
1334						}
1335					}
1336				}
1337			}
1338			ready = append(ready, b)
1339		}
1340	
1341		sortBeadsForQueue(ready)
1342	
1343		return ready, nil
1344	}
