1346	// Blocked returns open beads with at least one unclosed dependency.
1347	func (s *Store) Blocked() ([]Bead, error) {
1348		beads, err := s.ReadAll()
1349		if err != nil {
1350			return nil, err
1351		}
1352		statusMap := make(map[string]string)
1353		for _, b := range beads {
1354			statusMap[b.ID] = b.Status
1355		}
1356	
1357		var blocked []Bead
1358		for _, b := range beads {
1359			if b.Status != StatusOpen {
1360				continue
1361			}
1362			for _, depID := range b.DepIDs() {
1363				if statusMap[depID] != StatusClosed {
1364					blocked = append(blocked, b)
1365					break
1366				}
1367			}
1368		}
1369		sortBeadsForQueue(blocked)
1370		return blocked, nil
1371	}
1372	
1373	// BlockedAll returns open beads that are currently not runnable, classified
1374	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1375	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1376	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1377	// that is both dep-blocked and cooldown-parked is reported as dependency-
1378	// blocked, because deps are the stronger blocker.
1379	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1380		beads, err := s.ReadAll()
1381		if err != nil {
1382			return nil, err
1383		}
1384		statusMap := make(map[string]string)
1385		for _, b := range beads {
1386			statusMap[b.ID] = b.Status
1387		}
1388	
1389		now := time.Now().UTC()
1390		var entries []BlockedBead
1391		for _, b := range beads {
1392			if b.Status != StatusOpen {
1393				continue
1394			}
1395	
1396			var unclosed []string
1397			for _, depID := range b.DepIDs() {
1398				if statusMap[depID] != StatusClosed {
1399					unclosed = append(unclosed, depID)
1400				}
1401			}
1402			if len(unclosed) > 0 {
1403				entries = append(entries, BlockedBead{
1404					Bead: b,
1405					Blocker: Blocker{
1406						Kind:           BlockerKindDependency,
1407						UnclosedDepIDs: unclosed,
1408					},
1409				})
1410				continue
1411			}
1412	
1413			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1414			if !ok {
1415				continue
1416			}
1417			retryAfterStr, isStr := retryAfterRaw.(string)
1418			if !isStr || retryAfterStr == "" {
1419				continue
1420			}
1421			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1422			if err != nil || !retryAfter.After(now) {
1423				continue
1424			}
1425			blocker := Blocker{
1426				Kind:           BlockerKindRetryCooldown,
1427				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1428			}
1429			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1430				if s, ok := v.(string); ok {
1431					blocker.LastStatus = s
1432				}
1433			}
1434			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1435				if s, ok := v.(string); ok {
1436					blocker.LastDetail = s
1437				}
1438			}
1439			entries = append(entries, BlockedBead{
1440				Bead:    b,
1441				Blocker: blocker,
1442			})
1443		}
1444	
1445		sort.SliceStable(entries, func(i, j int) bool {
1446			if entries[i].Priority != entries[j].Priority {
1447				return entries[i].Priority < entries[j].Priority
1448			}
1449			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1450				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1451			}
1452			return entries[i].ID < entries[j].ID
1453		})
1454		return entries, nil
1455	}
1456	
1457	func sortBeadsForQueue(beads []Bead) {
1458		sort.SliceStable(beads, func(i, j int) bool {
1459			if beads[i].Priority != beads[j].Priority {
1460				return beads[i].Priority < beads[j].Priority
1461			}
1462			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1463				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1464			}
1465			return beads[i].ID < beads[j].ID
1466		})
1467	}
