1469	// Status returns aggregate counts.
1470	func (s *Store) Status() (*StatusCounts, error) {
1471		beads, err := s.ReadAll()
1472		if err != nil {
1473			return nil, err
1474		}
1475		ready, err := s.Ready()
1476		if err != nil {
1477			return nil, err
1478		}
1479		blocked, err := s.Blocked()
1480		if err != nil {
1481			return nil, err
1482		}
1483	
1484		// Pull in archive partner so totals survive `bead migrate` — the archive
1485		// only carries closed beads, so Ready/Blocked aren't affected.
1486		seen := make(map[string]bool, len(beads))
1487		all := make([]Bead, 0, len(beads))
1488		for _, b := range beads {
1489			if seen[b.ID] {
1490				continue
1491			}
1492			seen[b.ID] = true
1493			all = append(all, b)
1494		}
1495		if s.Collection == DefaultCollection {
1496			archive := s.archivePartner()
1497			if archived, aerr := archive.ReadAll(); aerr == nil {
1498				for _, b := range archived {
1499					if seen[b.ID] {
1500						continue
1501					}
1502					seen[b.ID] = true
1503					all = append(all, b)
1504				}
1505			}
1506		}
1507	
1508		counts := &StatusCounts{Total: len(all), Ready: len(ready), Blocked: len(blocked)}
1509		for _, b := range all {
1510			switch b.Status {
1511			case StatusOpen:
1512				counts.Open++
1513			case StatusClosed:
1514				counts.Closed++
1515			}
1516		}
1517		return counts, nil
1518	}
