1520	// DepAdd adds a dependency: id depends on depID.
1521	func (s *Store) DepAdd(id, depID string) error {
1522		return s.WithLock(func() error {
1523			beads, _, err := s.readAllLatestRaw()
1524			if err != nil {
1525				return err
1526			}
1527			var target *Bead
1528			depExists := false
1529			for i := range beads {
1530				if beads[i].ID == id {
1531					target = &beads[i]
1532				}
1533				if beads[i].ID == depID {
1534					depExists = true
1535				}
1536			}
1537			if target == nil {
1538				return fmt.Errorf("bead: not found: %s", id)
1539			}
1540			if !depExists {
1541				return fmt.Errorf("bead: dependency not found: %s", depID)
1542			}
1543			if id == depID {
1544				return fmt.Errorf("bead: cannot depend on self")
1545			}
1546			if target.HasDep(depID) {
1547				return nil // already exists
1548			}
1549	
1550			// Check for circular dependency
1551			depMap := make(map[string][]string)
1552			for _, b := range beads {
1553				depMap[b.ID] = b.DepIDs()
1554			}
1555			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1556			if hasCycle(depMap, id) {
1557				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1558			}
1559	
1560			target.AddDep(depID, "blocks")
1561			target.UpdatedAt = time.Now().UTC()
1562			return s.WriteAll(beads)
1563		})
1564	}
