1573	// DepTree returns a text representation of the dependency tree.
1574	func (s *Store) DepTree(rootID string) (string, error) {
1575		beads, err := s.ReadAll()
1576		if err != nil {
1577			return "", err
1578		}
1579		// Pull in archive partner so the tree survives `bead migrate` — closed
1580		// beads stored only in the archive must still appear.
1581		if s.Collection == DefaultCollection {
1582			archive := s.archivePartner()
1583			if archived, aerr := archive.ReadAll(); aerr == nil {
1584				seen := make(map[string]bool, len(beads))
1585				for _, b := range beads {
1586					seen[b.ID] = true
1587				}
1588				for _, b := range archived {
1589					if seen[b.ID] {
1590						continue
1591					}
1592					beads = append(beads, b)
1593				}
1594			}
1595		}
1596		byID := make(map[string]*Bead)
1597		for i := range beads {
1598			byID[beads[i].ID] = &beads[i]
1599		}
1600	
1601		if rootID != "" {
1602			target, ok := byID[rootID]
1603			if !ok {
1604				return "", fmt.Errorf("bead: not found: %s", rootID)
1605			}
1606			var sb strings.Builder
1607			// Walk up: show the dependency chain (what this node depends on)
1608			depChain := s.depChainUp(byID, rootID)
1609			if len(depChain) > 0 {
1610				// Print deps as the tree root(s), with the target as their child
1611				for _, depID := range depChain {
1612					if dep, ok := byID[depID]; ok {
1613						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1614					}
1615				}
1616			}
1617			// Print the target node
1618			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1619			// Print dependents (what depends on this node)
1620			var children []string
1621			for _, other := range sortedKeys(byID) {
1622				if byID[other].HasDep(rootID) {
1623					children = append(children, other)
1624				}
1625			}
1626			for _, child := range children {
1627				s.printTree(&sb, byID, child, "  ", true)
1628			}
1629			return sb.String(), nil
1630		}
1631	
1632		// Find roots (beads that have no dependencies themselves)
1633		var roots []string
1634		for _, b := range beads {
1635			if len(b.Dependencies) == 0 {
1636				roots = append(roots, b.ID)
1637			}
1638		}
1639		sort.Strings(roots)
1640	
1641		var sb strings.Builder
1642		for i, root := range roots {
1643			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1644		}
1645		return sb.String(), nil
1646	}
1647	
1648	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1649		b, ok := byID[id]
1650		if !ok {
1651			return
1652		}
1653	
1654		connector := "├── "
1655		if last {
1656			connector = "└── "
1657		}
1658		if prefix == "" {
1659			connector = ""
1660		}
1661	
1662		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1663	
1664		// Find beads that depend on this one (children in the tree)
1665		var children []string
1666		for _, other := range sortedKeys(byID) {
1667			if byID[other].HasDep(id) {
1668				children = append(children, other)
1669			}
1670		}
1671	
1672		childPrefix := prefix
1673		if prefix != "" {
1674			if last {
1675				childPrefix += "    "
1676			} else {
1677				childPrefix += "│   "
1678			}
1679		}
1680	
1681		for i, child := range children {
1682			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1683		}
1684	}
1685	
1686	// depChainUp returns the direct dependencies of a bead (upstream IDs).
1687	func (s *Store) depChainUp(byID map[string]*Bead, id string) []string {
1688		b, ok := byID[id]
1689		if !ok {
1690			return nil
1691		}
1692		return b.DepIDs()
1693	}
