1695	// validateBead checks core invariants that must hold for any bead (create or update).
1696	func (s *Store) validateBead(b *Bead) error {
1697		if strings.TrimSpace(b.Title) == "" {
1698			return fmt.Errorf("bead: title is required")
1699		}
1700		if b.Priority < MinPriority || b.Priority > MaxPriority {
1701			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
1702		}
1703		if b.Status != StatusOpen && b.Status != StatusInProgress && b.Status != StatusClosed && b.Status != StatusBlocked {
1704			return fmt.Errorf("bead: invalid status: %s", b.Status)
1705		}
1706		// Self-ref check
1707		for _, depID := range b.DepIDs() {
1708			if depID == b.ID && b.ID != "" {
1709				return fmt.Errorf("bead: cannot depend on self")
1710			}
1711		}
1712		return nil
1713	}
1714	
1715	// detectPrefix derives the bead ID prefix from the repository/directory name,
1716	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
1717	// workingDir is the project root to use for git commands; when empty the
1718	// process working directory is used (legacy behaviour, prone to worktree
1719	// path contamination). Falls back to DefaultPrefix if detection fails.
1720	func detectPrefix(workingDir string) string {
1721		// Try git repo root name first, running from the known project root so
1722		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
1723		// contaminate the prefix with their ephemeral directory names.
1724		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
1725		if out, err := cmd.Output(); err == nil {
1726			root := strings.TrimSpace(string(out))
1727			if root != "" {
1728				return filepath.Base(root)
1729			}
1730		}
1731		// Fall back to the provided working dir, then cwd.
1732		if workingDir != "" {
1733			return filepath.Base(workingDir)
1734		}
1735		if wd, err := os.Getwd(); err == nil {
1736			return filepath.Base(wd)
1737		}
1738		return DefaultPrefix
1739	}
1740	
1741	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
1742		v := os.Getenv(envKey)
1743		if v == "" {
1744			return fallback
1745		}
1746		// Try as seconds (plain number)
1747		if secs, err := strconv.ParseFloat(v, 64); err == nil {
1748			return time.Duration(secs * float64(time.Second))
1749		}
1750		// Try as Go duration
1751		if d, err := time.ParseDuration(v); err == nil {
1752			return d
1753		}
1754		return fallback
1755	}
1756	
1757	func envOr(key, fallback string) string {
1758		if v := os.Getenv(key); v != "" {
1759			return v
1760		}
1761		return fallback
1762	}
