1764	func containsString(ss []string, s string) bool {
1765		for _, v := range ss {
1766			if v == s {
1767				return true
1768			}
1769		}
1770		return false
1771	}
1772	
1773	func sortedKeys(m map[string]*Bead) []string {
1774		keys := make([]string, 0, len(m))
