2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strconv"
8		"strings"
9		"time"
10	)
11	
12	// StaleLockAge is the duration after which a lock is considered stale
13	// and can be forcibly broken. Default: 2 hours.
14	var StaleLockAge = 2 * time.Hour
15	
16	// WithLock acquires the file lock, runs fn, then releases the lock.
17	// For external backends, locking is delegated to the backend tool.
18	func (s *Store) WithLock(fn func() error) error {
19		if s.backend != nil {
20			return s.backend.WithLock(fn)
21		}
22		if err := s.acquireLock(); err != nil {
23			return err
24		}
25		defer s.releaseLock()
26		return fn()
27	}
28	
29	func (s *Store) acquireLock() error {
30		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
31			return fmt.Errorf("bead: lock dir: %w", err)
32		}
33	
34		deadline := time.Now().Add(s.LockWait)
35		for {
36			err := os.Mkdir(s.LockDir, 0o755)
37			if err == nil {
38				// Write PID and acquired_at
39				_ = os.WriteFile(filepath.Join(s.LockDir, "pid"),
40					[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
41				_ = os.WriteFile(filepath.Join(s.LockDir, "acquired_at"),
42					[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
43				return nil
44			}
45	
46			// Check for stale lock
47			if s.breakStaleLock() {
48				continue // retry immediately after breaking
49			}
50	
51			if time.Now().After(deadline) {
52				owner := "unknown"
53				pidData, _ := os.ReadFile(filepath.Join(s.LockDir, "pid"))
54				if len(pidData) > 0 {
55					owner = strings.TrimSpace(string(pidData))
56				}
57				return fmt.Errorf("bead: lock timeout (owner pid: %s)", owner)
58			}
59			time.Sleep(50 * time.Millisecond)
60		}
61	}
62	
63	// breakStaleLock checks if the existing lock is stale (owner dead or too old)
64	// and breaks it if so. Returns true if lock was broken.
65	func (s *Store) breakStaleLock() bool {
66		// Check if owner PID is still alive (skip if it's our own PID)
67		pidData, err := os.ReadFile(filepath.Join(s.LockDir, "pid"))
68		if err == nil {
69			pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
70			if err == nil && pid > 0 && pid != os.Getpid() {
71				if !processAlive(pid) {
72					// Process is dead — break the lock
73					os.RemoveAll(s.LockDir)
74					return true
75				}
76			}
77		}
78	
79		// Check age
80		acquiredData, err := os.ReadFile(filepath.Join(s.LockDir, "acquired_at"))
81		if err == nil {
82			acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
83			if err == nil && time.Since(acquired) > StaleLockAge {
84				os.RemoveAll(s.LockDir)
85				return true
86			}
87		}
88	
89		return false
90	}
91	
92	func (s *Store) releaseLock() {
93		os.RemoveAll(s.LockDir)
94	}
